import{_ as e,o as t,c as o,ag as l}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/faq.md","filePath":"guide/help/faq.md","lastUpdated":1780491682000}'),r={name:"guide/help/faq.md"};function i(h,a,d,s,p,n){return t(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="默认访问地址是什么" tabindex="-1">默认访问地址是什么 <a class="header-anchor" href="#默认访问地址是什么" aria-label="Permalink to &quot;默认访问地址是什么&quot;">​</a></h2><p>默认端口是 <code>16868</code>。</p><p>本机访问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:16868</span></span></code></pre></div><p>服务器或 NAS 访问时，把 <code>localhost</code> 换成设备 IP 或域名。</p><h2 id="为什么-compose-示例使用-host-网络" tabindex="-1">为什么 Compose 示例使用 host 网络 <a class="header-anchor" href="#为什么-compose-示例使用-host-网络" aria-label="Permalink to &quot;为什么 Compose 示例使用 host 网络&quot;">​</a></h2><p>host 网络下，应用监听的端口就是宿主机端口，不需要写 <code>ports</code> 映射。PanSave 后续可能会有更多本机端口能力，例如 302 反代相关功能，host 网络更省维护。</p><p>如果你的 Docker 环境不支持 host 网络，可以按 <a href="/guide/deploy/docker#如果-host-网络不可用">Docker 部署</a> 里的端口映射示例改回 bridge 模式。</p><h2 id="需要备份哪些文件" tabindex="-1">需要备份哪些文件 <a class="header-anchor" href="#需要备份哪些文件" aria-label="Permalink to &quot;需要备份哪些文件&quot;">​</a></h2><p>至少备份整个 <code>data</code> 目录。</p><p>里面保存系统配置、登录状态、Telegram 会话和日志。迁移机器时，建议把整个 <code>data</code> 目录一起带走，不要只挑单个文件。</p><h2 id="修改密码后为什么要重新登录" tabindex="-1">修改密码后为什么要重新登录 <a class="header-anchor" href="#修改密码后为什么要重新登录" aria-label="Permalink to &quot;修改密码后为什么要重新登录&quot;">​</a></h2><p>登录状态会绑定当前管理员账号和密码版本。修改密码后，旧登录状态会失效，这是为了避免旧会话继续可用。</p><h2 id="频道已经添加了-为什么频道扫描里没有任务" tabindex="-1">频道已经添加了，为什么频道扫描里没有任务 <a class="header-anchor" href="#频道已经添加了-为什么频道扫描里没有任务" aria-label="Permalink to &quot;频道已经添加了，为什么频道扫描里没有任务&quot;">​</a></h2><p>常见原因：</p><ul><li>当前 Telegram 模式不一致，例如添加的是 API 频道，但现在切到公开频道模式。</li><li>频道没有在频道扫描里启用。</li><li>频道没有关联网盘账号。</li><li>关联的网盘没有整理源目录。</li><li>网盘账号已禁用或失效。</li></ul><p>频道资源池只是可用列表，具体是否参与扫描要在频道扫描里单独配置。</p><h2 id="监控策略里启用了频道-为什么豆瓣求片仍然不搜索" tabindex="-1">监控策略里启用了频道，为什么豆瓣求片仍然不搜索 <a class="header-anchor" href="#监控策略里启用了频道-为什么豆瓣求片仍然不搜索" aria-label="Permalink to &quot;监控策略里启用了频道，为什么豆瓣求片仍然不搜索&quot;">​</a></h2><p>先检查：</p><ul><li>当前 Emby 是否选对。</li><li>监控策略总开关是否开启。</li><li>搜索来源是否在当前 Telegram 模式下可见。</li><li>来源是否关联网盘，网盘是否有整理源目录。</li><li>豆瓣求片总开关是否开启。</li></ul><p>豆瓣求片继承监控策略来源，不读取频道扫描的启用状态。</p><h2 id="为什么扫描到了资源但没有自动转存" tabindex="-1">为什么扫描到了资源但没有自动转存 <a class="header-anchor" href="#为什么扫描到了资源但没有自动转存" aria-label="Permalink to &quot;为什么扫描到了资源但没有自动转存&quot;">​</a></h2><p>频道扫描默认拆成两步：先扫描，再手动转存。这是为了让你先确认关键词和命中结果，避免错误资源被自动存入网盘。</p><p>监控策略、榜单订阅、豆瓣求片这类自动流程才会按规则自动转存。</p><h2 id="emby-缺集扫描和监控清单是什么关系" tabindex="-1">Emby 缺集扫描和监控清单是什么关系 <a class="header-anchor" href="#emby-缺集扫描和监控清单是什么关系" aria-label="Permalink to &quot;Emby 缺集扫描和监控清单是什么关系&quot;">​</a></h2><p>缺集扫描是一次快照，用来找出当前媒体库里可能缺少的剧集。监控清单是长期跟踪列表。</p><p>你可以把缺集扫描结果加入监控清单，但缺集扫描本身不会直接覆盖监控清单的状态。</p><h2 id="代理会影响哪些功能" tabindex="-1">代理会影响哪些功能 <a class="header-anchor" href="#代理会影响哪些功能" aria-label="Permalink to &quot;代理会影响哪些功能&quot;">​</a></h2><p>代理只影响 Telegram 和 TMDB。</p><p>豆瓣、Emby、网盘接口等请求不使用这里的代理。如果某个 Emby 地址在内网，确保部署 PanSave 的机器能直接访问它。</p><h2 id="授权码保存失败怎么办" tabindex="-1">授权码保存失败怎么办 <a class="header-anchor" href="#授权码保存失败怎么办" aria-label="Permalink to &quot;授权码保存失败怎么办&quot;">​</a></h2><p>先确认授权码复制完整、当前机器可以访问互联网。如果页面仍提示失败，保留错误提示或截图，到 <a href="https://t.me/pansavechat" target="_blank" rel="noreferrer">Telegram 群组</a> 联系管理员排查。</p><h2 id="授权码从哪里获得" tabindex="-1">授权码从哪里获得 <a class="header-anchor" href="#授权码从哪里获得" aria-label="Permalink to &quot;授权码从哪里获得&quot;">​</a></h2><p>可以通过 <a href="/donate">捐助支持</a> 获取授权码感谢回馈。捐助用于鼓励开发和支持项目维护，不是购买资源或资源服务。</p>',35)])])}const m=e(r,[["render",i]]);export{u as __pageData,m as default};
